#include <iostream>

// The function under test is expected to be available
void swap_integers(int* a, int* b);

int main() {
    int x = 5;
    int y = 10;
    swap_integers(&x, &y);
    std::cout << x << " " << y << std::endl;

    int a = -1;
    int b = 0;
    swap_integers(&a, &b);
    std::cout << a << " " << b << std::endl;

    int p = 7;
    int q = 7;
    swap_integers(&p, &q);
    std::cout << p << " " << q << std::endl;

    return 0;
}
